import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class KeyboardInputBar extends StatefulWidget { final ValueChanged<String> onSend; const KeyboardInputBar({super.key, required this.onSend}); @override State<KeyboardInputBar> createState() => _KeyboardInputBarState(); } class _KeyboardInputBarState extends State<KeyboardInputBar> { final _ctrl = TextEditingController(); @override void dispose() { _ctrl.dispose(); super.dispose(); } @override Widget build(BuildContext context) => Row(children: [Expanded(child: TextField(controller: _ctrl, style: const TextStyle(color: AppTheme.darkText, fontSize: 14), decoration: const InputDecoration(hintText: 'Type text...', hintStyle: TextStyle(color: AppTheme.darkSubtext), filled: true, fillColor: AppTheme.darkCard, border: InputBorder.none, contentPadding: EdgeInsets.symmetric(horizontal: 14, vertical: 10)))), IconButton(icon: const Icon(Icons.send, color: AppTheme.primaryColor), onPressed: () { if (_ctrl.text.isNotEmpty) { widget.onSend(_ctrl.text); _ctrl.clear(); } })]); }